#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int leastInterval(vector<int>& tasks, int n) {
        unordered_map<int, int> count;
        for (int task : tasks) {
            count[task]++;
        }
        int maxFreq = 0;
        int maxFreqTask = 0;
        for (auto& pair : count) {
            if (pair.second > maxFreq) {
                maxFreq = pair.second;
                maxFreqTask = 1;
            } else if (pair.second == maxFreq) {
                maxFreqTask++;
            }
        }
        int ans = (maxFreq - 1) * (n + 1) + maxFreqTask;
        return max((int)tasks.size(), ans);
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    vector<int> tasks(n);
    for (int i = 0; i < n; i++) cin >> tasks[i];
    int cooldown;
    cin >> cooldown;
    Solution sol;
    int ans = sol.leastInterval(tasks, cooldown);
    cout << ans << '\n';
    return 0;
}
